import React, { useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, MoneyInput, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import { DocumentFormHeader } from '../../../components/layout';
import { CustomerSearchField } from '../../../components/search';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { customerFieldHandlers, loadCustomerDisplay } from '../../../utils/customerField';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'bh-hop-dong-form';

const STATUS_OPTIONS = [
  { value: 'Draft', label: 'Nháp' },
  { value: 'Active', label: 'Hiệu lực' },
  { value: 'Closed', label: 'Đã đóng' },
  { value: 'Cancelled', label: 'Đã hủy' },
];

const HopDongFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [contractDate, setContractDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerId, setCustomerId] = useState('');
  const [customerCode, setCustomerCode] = useState('');
  const [customerName, setCustomerName] = useState('');
  const [description, setDescription] = useState('');
  const [totalAmount, setTotalAmount] = useState(0);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [status, setStatus] = useState('Draft');
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  const customerHandlers = useMemo(
    () => customerFieldHandlers(setCustomerId, setCustomerCode, setCustomerName),
    [],
  );

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      bhService.getContract(id)
        .then(async c => {
          if (cancelled) return;
          setContractDate(c.contractDate.slice(0, 10));
          setCustomerId(c.customerId);
          setDescription(c.description ?? '');
          setTotalAmount(c.totalAmount);
          setStartDate(c.startDate?.slice(0, 10) ?? '');
          setEndDate(c.endDate?.slice(0, 10) ?? '');
          setStatus(c.status);
          const display = await loadCustomerDisplay(c.customerId, c.customerName);
          if (!cancelled) {
            setCustomerCode(display.code);
            setCustomerName(display.name);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải hợp đồng'),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const handleSave = async () => {
    if (!customerId) {
      dispatchAppToast(dispatch, { message: 'Chọn khách hàng', type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (isEdit && id) {
        await bhService.updateContract(id, {
          customerId,
          description,
          totalAmount,
          startDate: startDate || undefined,
          endDate: endDate || undefined,
          status,
        });
        dispatchAppToast(dispatch, { message: 'Cập nhật hợp đồng thành công', type: 'success' });
        navigate(`/bh/hd/${id}`);
      } else {
        const created = await bhService.createContract({
          contractDate,
          customerId,
          description,
          totalAmount,
          startDate: startDate || undefined,
          endDate: endDate || undefined,
        });
        dispatchAppToast(dispatch, { message: 'Tạo hợp đồng thành công', type: 'success' });
        navigate(`/bh/hd/${created.id}`);
      }
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading} data-testid={`${TEST_ID}-loading`}>Đang tải...</div>;

  return (
    <div className={df.page} data-testid={TEST_ID}>
      <DocumentFormHeader
        onBack={() => navigate('/bh/hd')}
        title={isNew ? 'Tạo hợp đồng' : 'Sửa hợp đồng'}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo hợp đồng"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin hợp đồng</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày hợp đồng</label>
            <Input
              type="date"
              value={contractDate}
              onChange={e => setContractDate(e.target.value)}
              disabled={isEdit}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Khách hàng</label>
            <CustomerSearchField
              customerId={customerId}
              customerCode={customerCode}
              customerName={customerName}
              onSelect={customerHandlers.onSelect}
              onClear={customerHandlers.onClear}
              testIdPrefix={`${TEST_ID}-customer`}
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Giá trị</label>
            <MoneyInput
              value={totalAmount}
              onChange={setTotalAmount}
              data-testid={`${TEST_ID}-field-totalAmount`}
            />
          </div>
          {isEdit ? (
            <div className={df.field}>
              <label className={df.label}>Trạng thái</label>
              <Select value={status} onChange={e => setStatus(e.target.value)} options={STATUS_OPTIONS} />
            </div>
          ) : null}
          <div className={df.field}>
            <label className={df.label}>Từ ngày</label>
            <Input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Đến ngày</label>
            <Input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Diễn giải</label>
            <Input value={description} onChange={e => setDescription(e.target.value)} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default HopDongFormPage;
